import{_ as e,o as l,c as t,a5 as i}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"教程 0040：两电平 SVPWM","description":"","frontmatter":{"title":"教程 0040：两电平 SVPWM","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0040-two-level-svpwm.html","status":"learning","visibility":"public","summary":"Imported from 0040-two-level-svpwm.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0040-two-level-svpwm.md","filePath":"content/power/lessons/0040-two-level-svpwm.md","lastUpdated":null}'),o={name:"content/power/lessons/0040-two-level-svpwm.md"};function r(s,a,n,p,h,c){return l(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="教程-0040-两电平-svpwm" tabindex="-1">教程 0040：两电平 SVPWM <a class="header-anchor" href="#教程-0040-两电平-svpwm" aria-label="Permalink to &quot;教程 0040：两电平 SVPWM&quot;">​</a></h1><p>中文主讲。一个概念：空间矢量脉宽调制把 alpha/beta 电压矢量合成为三相桥臂占空比。</p><p>目录</p><ul><li>它是什么</li><li>为什么 UPS 需要它</li><li>物理直觉</li><li>数学形式</li><li>一个仿真任务与仿真观察</li><li>固件落地</li><li>常见误解</li><li>验收标准、复盘问题、导师问题</li></ul><p>**保密边界：**只使用两电平教学算法，不记录真实 PWM 同步、死区补偿或驱动保护细节。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>空间矢量脉宽调制（space vector pulse-width modulation / SVPWM）把三相两电平逆变桥的 8 个开关状态看成 6 个有效矢量和 2 个零矢量，在一个 PWM 周期内用相邻矢量平均合成目标电压。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>三相逆变器、三相有源整流器和 PCS 都需要把 dq 控制器输出的电压参考变成 PWM。SVPWM 比简单 SPWM 电压利用率更高，也更容易扩展到三电平调制。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>目标电压矢量落在哪个扇区，就用扇区两边的两个基本矢量加零矢量拼出来。占用时间越长，平均电压越靠近那个矢量。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>sector = angle(v_alpha, v_beta) T1, T2 = adjacent_vector_times(v_alpha, v_beta, Vdc, Ts) T0 = Ts - T1 - T2 Ta, Tb, Tc = sequence_to_duty(T1, T2, T0)</p><p>工程中也常用 min-max 注入法快速得到占空比，本质上等价于给三相调制波注入零序分量。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>设置调制比从 0.2 扫到 0.9，画出三相占空比和 alpha/beta 目标矢量轨迹。观察过调制前后占空比是否触碰 0 或 1。</p><p>产物</p><ul><li>一张三相占空比曲线。</li><li>一张六扇区矢量轨迹草图。</li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>固件路径通常是 <code>dq voltage -&gt; inverse Park -&gt; SVPWM -&gt; PWM compare register</code>。更新比较值前要处理限幅、死区、互补输出和故障封锁。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li>**误解：**SVPWM 只是一种波形画法。 **纠正：**它直接决定桥臂开关时序。</li><li>**误解：**扇区判断错只会轻微失真。 **纠正：**可能导致占空比跳变和过流。</li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能列出 6 个有效矢量和 2 个零矢量。</li><li>能解释 T1、T2、T0 的物理含义。</li><li>能说出 min-max 注入与零序注入的关系。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>为什么 SVPWM 电压利用率比 SPWM 高？</li><li>过调制时控制器应该先限幅还是继续输出？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>三相 UPS 或 PCS 代码里，SVPWM 是扇区法、min-max 法，还是查表法？</li><li>我只确认阅读入口，不记录内部时序细节。</li></ul><p>**下一步：**进入三相 UPS 前级：Vienna PFC 和中点电压平衡。</p><p>源稿：<code>concepts/power-electronics/two-level-svpwm.md</code></p><p>上一节：教程 0039：三相 dq 电流环解耦下一节：教程 0041：Vienna PFC 与中点电压平衡</p>',31)])])}const _=e(o,[["render",r]]);export{u as __pageData,_ as default};
